mapper.select:
SELECT p.product_id, p.category_id, c.category_name, p.product_code, p.product_name, p.product_subname, p.status, p.is_featured, p.is_active, p.transport_type, p.video_path, p.video_url, p.created_at, p.updated_at, thumb.image_path AS thumbnail_path, (SELECT COUNT(*) FROM product_images pi WHERE pi.product_id = p.product_id) AS image_count, (SELECT COUNT(*) FROM product_files pf WHERE pf.product_id = p.product_id) AS file_count, ( COALESCE((SELECT COUNT(*) FROM cruise_itineraries WHERE product_id = p.product_id), 0) + COALESCE((SELECT COUNT(*) FROM air_itineraries WHERE product_id = p.product_id), 0) + COALESCE((SELECT COUNT(*) FROM domestic_itineraries WHERE product_id = p.product_id), 0) + COALESCE((SELECT COUNT(*) FROM school_trip_itineraries WHERE product_id = p.product_id), 0) ) AS itinerary_count, ( EXISTS (SELECT 1 FROM cruise_details WHERE product_id = p.product_id) OR EXISTS (SELECT 1 FROM air_details WHERE product_id = p.product_id) OR EXISTS (SELECT 1 FROM domestic_details WHERE product_id = p.product_id) OR EXISTS (SELECT 1 FROM school_trip_details WHERE product_id = p.product_id) ) AS has_detail FROM products p LEFT JOIN categories c ON p.category_id = c.category_id LEFT JOIN product_images thumb ON thumb.product_id = p.product_id AND thumb.image_type = 'THUMBNAIL'
AND p.category_id = #{search.categoryId}
AND p.status = #{search.status}
AND p.is_featured = #{search.isFeatured}
AND p.is_active = #{search.isActive}
AND ( p.product_name LIKE '%' || #{search.keyword} || '%' OR p.product_code LIKE '%' || #{search.keyword} || '%' )
ORDER BY p.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM products p


        AND p.category_id = #{search.categoryId}


        AND p.status = #{search.status}


        AND p.is_featured = #{search.isFeatured}


        AND p.is_active = #{search.isActive}


        AND (
            p.product_name LIKE '%' || #{search.keyword} || '%'
            OR p.product_code LIKE '%' || #{search.keyword} || '%'
        )

SELECT COUNT(*)
FROM products
WHERE product_code = #{productCode}

    AND product_id <> #{excludeId}

